import{_ as t,a as i,b as a}from"./chunks/支持留言.NiGCLVdp.js";import{_ as n,o as s,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Blog verwenden","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/blog.md","filePath":"de-DE/Other/blog.md","lastUpdated":1781962217000}'),o={name:"de-DE/Other/blog.md"};function d(p,e,g,c,u,h){return s(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="blog-verwenden" tabindex="-1">Blog verwenden <a class="header-anchor" href="#blog-verwenden" aria-label="Permalink to &quot;Blog verwenden&quot;">​</a></h1><p>Mit der Blog-Funktion fügst du deiner ImgBed-Seite eine eigenständige Blog-Seite hinzu.</p><p>Nach dem Aktivieren ist sie unter dieser Adresse erreichbar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://deine-domain/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog-Startseite" loading="lazy"></p><p>Der Blog basiert auf dem Open-Source-Projekt <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> und wurde für ImgBed mit Vue neu eingebunden.</p><h2 id="wo-einstellen" tabindex="-1">Wo einstellen <a class="header-anchor" href="#wo-einstellen" aria-label="Permalink to &quot;Wo einstellen&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Systemeinstellungen -&gt; Weitere Einstellungen -&gt; Blog</span></span></code></pre></div><p><img src="'+i+'" alt="Blog-Einstellungen" loading="lazy"></p><h2 id="ersteinrichtung" tabindex="-1">Ersteinrichtung <a class="header-anchor" href="#ersteinrichtung" aria-label="Permalink to &quot;Ersteinrichtung&quot;">​</a></h2><ol><li>Aktiviere <code>Aktivieren</code>.</li><li>Wähle das GitHub-Konto aus, in dem die Blog-Konfiguration gespeichert werden soll.</li><li>Klicke auf <code>Blog aktualisieren</code>.</li><li>Warte auf die Erfolgsmeldung.</li><li>Öffne <code>https://deine-domain/blog/</code> und prüfe das Ergebnis.</li></ol><p>Beim ersten Start legt ImgBed im ausgewählten GitHub-Konto ein privates Repository an:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Darin werden Blog-Einstellungen und Beiträge gespeichert.</p><h2 id="beitrage-schreiben" tabindex="-1">Beiträge schreiben <a class="header-anchor" href="#beitrage-schreiben" aria-label="Permalink to &quot;Beiträge schreiben&quot;">​</a></h2><p>Beiträge bearbeitest du im privaten GitHub-Repository:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typischer Ablauf:</p><ol><li>Öffne GitHub.</li><li>Gehe in das Repository <code>imgbed-blog-config</code>.</li><li>Erstelle oder bearbeite Beitragsdateien.</li><li>Committe die Änderungen.</li><li>Kehre zum ImgBed-Adminbereich zurück und klicke auf <code>Blog aktualisieren</code>. Alternativ kannst du im Blog oben links dreimal auf das Logo klicken, um eine Aktualisierung auszulösen.</li></ol><p><code>Blog aktualisieren</code> überschreibt keine bereits geschriebenen Beiträge. Die Aktion dient vor allem zum Initialisieren des Repositories und zum Aktualisieren des Caches.</p><h2 id="unterstutzte-funktionen" tabindex="-1">Unterstützte Funktionen <a class="header-anchor" href="#unterstutzte-funktionen" aria-label="Permalink to &quot;Unterstützte Funktionen&quot;">​</a></h2><p>Der Blog unterstützt Beitragslisten, Kategorien, Tags, Archive, Suche, Dark Mode und Sprachwechsel.</p><p>Kommentare und Besuchsstatistiken sind ebenfalls verfügbar.</p><p><img src="'+a+'" alt="Blog-Kommentare" loading="lazy"></p><p>Kommentare erscheinen unter dem jeweiligen Beitrag. Besucher können Avatar, Anzeigename, E-Mail-Adresse und Kommentartext angeben.</p><p>Die Statistik zeigt Seitenaufrufe von Beiträgen und Besuche der Website.</p><h2 id="adresse" tabindex="-1">Adresse <a class="header-anchor" href="#adresse" aria-label="Permalink to &quot;Adresse&quot;">​</a></h2><p>Der Blog liegt immer unter <code>/blog/</code>.</p><p>Wenn deine ImgBed-Domain so aussieht:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>dann lautet die Blog-Adresse:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Wenn du den Blog deaktivierst, können Besucher diese Seite nicht mehr öffnen.</p>',33)])])}const v=n(o,[["render",d]]);export{k as __pageData,v as default};
